function send(ws, message) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(message));
  }
}

function sendToPlayer(playerId, message) {
  const ws = sockets.get(playerId);
  if (ws) send(ws, message);
}

function broadcast(message) {
  const data = JSON.stringify(message);
  for (const ws of sockets.values()) {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(data);
    }
  }
}

function processMessage(ws, player, raw) {
  let msg;
  try {
    msg = JSON.parse(raw.toString());
  } catch {
    send(ws, { type: 'error', error: 'Invalid JSON' });
    return;
  }

  if (!msg || typeof msg !== 'object') {
    send(ws, { type: 'error', error: 'Invalid message' });
    return;
  }

  if (typeof msg.type !== 'string') {
    send(ws, { type: 'error', error: 'Missing message type' });
    return;
  }

  if (msg.type === 'ping') {
    send(ws, { type: 'pong', serverTime: Date.now() });
    return;
  }

  if (msg.type === 'sync') {
    send(ws, { type: 'state', state: serializeFullState() });
    return;
  }

  if (msg.type !== 'command') {
    send(ws, { type: 'error', error: 'Unknown message type' });
    return;
  }

  if (!msg.command || typeof msg.command !== 'object') {
    send(ws, { type: 'error', error: 'Missing command' });
    return;
  }

  processCommand(player, msg.command);
}

function processCommand(player, command) {
  const commandId = String(nextCommandId++);
  const action = command.action;

  if (typeof action !== 'string') {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Missing action' });
    return;
  }

  if (action === 'move') {
    handleMoveCommand(player, commandId, command);
    return;
  }

  if (action === 'attack') {
    handleAttackCommand(player, commandId, command);
    return;
  }

  if (action === 'build') {
    handleBuildCommand(player, commandId, command);
    return;
  }

  sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Unknown action' });
}

function handleMoveCommand(player, commandId, command) {
  const unitIds = Array.isArray(command.unitIds) ? command.unitIds.map(String) : [];
  const x = Number(command.x);
  const y = Number(command.y);

  if (!unitIds.length || !Number.isFinite(x) || !Number.isFinite(y)) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Invalid move payload' });
    return;
  }

  const tx = clamp(x, 0, WORLD_WIDTH);
  const ty = clamp(y, 0, WORLD_HEIGHT);
  const accepted = [];

  unitIds.forEach((unitId, index) => {
    const unit = game.units.get(unitId);
    if (!unit || unit.ownerId !== player.id) return;
    const offsetX = (index % 5) * 18 - 36;
    const offsetY = Math.floor(index / 5) * 18 - 18;
    unit.moveTarget = {
      x: clamp(tx + offsetX, 0, WORLD_WIDTH),
      y: clamp(ty + offsetY, 0, WORLD_HEIGHT),
    };
    unit.target = null;
    unit.state = 'moving';
    accepted.push(unit.id);
  });

  sendToPlayer(player.id, {
    type: 'commandAccepted',
    commandId,
    action: 'move',
    unitIds: accepted,
  });

  if (accepted.length) {
    broadcast({
      type: 'unitsUpdated',
      units: accepted.map(id => serializeUnit(game.units.get(id))),
    });
  }
}

function handleAttackCommand(player, commandId, command) {
  const unitIds = Array.isArray(command.unitIds) ? command.unitIds.map(String) : [];
  const targetId = command.targetId != null ? String(command.targetId) : null;

  if (!unitIds.length || !targetId) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Invalid attack payload' });
    return;
  }

  const targetUnit = game.units.get(targetId);
  const targetBuilding = game.buildings.get(targetId);
  const target = targetUnit || targetBuilding;

  if (!target) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Target not found' });
    return;
  }

  if (target.ownerId === player.id) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Cannot attack own target' });
    return;
  }

  const accepted = [];
  for (const unitId of unitIds) {
    const unit = game.units.get(unitId);
    if (!unit || unit.ownerId !== player.id) continue;
    unit.target = targetId;
    unit.moveTarget = null;
    unit.state = 'attacking';
    accepted.push(unit.id);
  }

  sendToPlayer(player.id, {
    type: 'commandAccepted',
    commandId,
    action: 'attack',
    unitIds: accepted,
    targetId,
  });

  if (accepted.length) {
    broadcast({
      type: 'unitsUpdated',
      units: accepted.map(id => serializeUnit(game.units.get(id))),
    });
  }
}

function handleBuildCommand(player, commandId, command) {
  const buildingId = command.buildingId != null ? String(command.buildingId) : player.baseId;
  const unitType = typeof command.unitType === 'string' ? command.unitType : 'worker';

  if (!UNIT_COST[unitType]) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Unknown unit type' });
    return;
  }

  const building = game.buildings.get(buildingId);
  if (!building || building.ownerId !== player.id) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Invalid building' });
    return;
  }

  const cost = UNIT_COST[unitType];
  if (player.resources < cost) {
    sendToPlayer(player.id, { type: 'commandRejected', commandId, reason: 'Not enough resources' });
    return;
  }

  player.resources -= cost;
  const queueItem = {
    id: String(nextCommandId++),
    unitType,
    remaining: BUILD_TIME,
    total: BUILD_TIME,
  };
  building.queue.push(queueItem);

  sendToPlayer(player.id, {
    type: 'commandAccepted',
    commandId,
    action: 'build',
    buildingId: building.id,
    queued: queueItem,
    resources: player.resources,
  });

  broadcast({
    type: 'playerUpdated',
    player: serializePlayer(player),
  });

  broadcast({
    type: 'buildingUpdated',
    building: serializeBuilding(building),
  });
}

function updateUnits(dt) {
  for (const unit of game.units.values()) {
    if (unit.cooldownRemaining > 0) {
      unit.cooldownRemaining = Math.max(0, unit.cooldownRemaining - dt);
    }

    let changed = false;

    if (unit.target) {
      const target = game.units.get(unit.target) || game.buildings.get(unit.target);
      if (!target || target.ownerId === unit.ownerId) {
        unit.target = null;
        if (unit.state === 'attacking') unit.state = 'idle';
        changed = true;
      } else {
        const dist = distance(unit, target);
        if (dist <= unit.range) {
          if (unit.cooldownRemaining <= 0) {
            target.hp -= unit.damage;
            unit.cooldownRemaining = unit.cooldown;
            changed = true;

            broadcast({
              type: 'combat',
              attackerId: unit.id,
              targetId: target.id,
              damage: unit.damage,
              targetHp: Math.max(0, target.hp),
            });

            if (target.hp <= 0) {
              if (game.units.has(target.id)) {
                destroyUnit(target.id);
              } else if (game.buildings.has(target.id)) {
                destroyBuilding(target.id);
              }
              unit.target = null;
              unit.state = 'idle';
            } else {
              if (game.units.has(target.id)) {
                broadcast({
                  type: 'unitUpdated',
                  unit: serializeUnit(target),
                });
              } else if (game.buildings.has(target.id)) {
                broadcast({
                  type: 'buildingUpdated',
                  building: serializeBuilding(target),
                });
              }
            }
          }
        } else {
          const dir = normalize(target.x - unit.x, target.y - unit.y);
          const step = Math.min(unit.speed * dt, dist - unit.range);
          if (step > 0) {
            unit.x += dir.x * step;
            unit.y += dir.y * step;
            unit.state = 'attacking';
            changed = true;
          }
        }
      }
    } else if (unit.moveTarget) {
      const dist = distance(unit, unit.moveTarget);
      if (dist <= 2) {
        unit.x = unit.moveTarget.x;
        unit.y = unit.moveTarget.y;
        unit.moveTarget = null;
        unit.state = 'idle';
        changed = true;
      } else {
        const dir = normalize(unit.moveTarget.x - unit.x, unit.moveTarget.y - unit.y);
        const step = Math.min(unit.speed * dt, dist);
        unit.x += dir.x * step;
        unit.y += dir.y * step;
        unit.state = 'moving';
        changed = true;
      }
    }

    if (changed) {
      broadcast({
        type: 'unitUpdated',
        unit: serializeUnit(unit),
      });
    }
  }
}

function updateBuildings(dt) {
  for (const building of game.buildings.values()) {
    if (!building.queue.length) continue;
    const item = building.queue[0];
    item.remaining -= dt;
    if (item.remaining <= 0) {
      const angle = Math.random() * Math.PI * 2;
      const radius = building.buildRadius + 20 + Math.random() * 20;
      const x = clamp(building.x + Math.cos(angle) * radius, 0, WORLD_WIDTH);
      const y = clamp(building.y + Math.sin(angle) * radius, 0, WORLD_HEIGHT);
      const unit = createUnit(building.ownerId, item.unitType, x, y);
      building.queue.shift();

      broadcast({
        type: 'unitCreated',
        unit: serializeUnit(unit),
      });

      const owner = players.get(building.ownerId);
      if (owner) {
        broadcast({
          type: 'playerUpdated',
          player: serializePlayer(owner),
        });
      }

      broadcast({
        type: 'buildingUpdated',
        building: serializeBuilding(building),
      });
    } else {
      broadcast({
        type: 'buildingUpdated',
        building: serializeBuilding(building),
      });
    }
  }
}

function gameLoop() {
  const now = Date.now();
  const dt = Math.min(0.1, (now - game.lastTick) / 1000);
  game.lastTick = now;
  updateUnits(dt);
  updateBuildings(dt);
}

const server = http.createServer((req, res) => {
  if (req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      ok: true,
      players: players.size,
      units: game.units.size,
      buildings: game.buildings.size,
      uptimeMs: Date.now() - game.startedAt,
    }));
    return;
  }

  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('RTS WebSocket server is running\n');
});

const wss = new WebSocket.Server({ server });

wss.on('connection', (ws, req) => {
  let player = null;

  ws.on('message', raw => {
    if (!player) {
      let join;
      try {
        join = JSON.parse(raw.toString());
      } catch {
        send(ws, { type: 'error', error: 'First message must be valid JSON join message' });
        ws.close();
        return;
      }

      if (!join || join.type !== 'join') {
        send(ws, { type: 'error', error: 'First message must be join' });
        ws.close();
        return;
      }

      player = createPlayer(ws, join.name);
      return;
    }

    processMessage(ws, player, raw);
  });

  ws.on('close', () => {
    if (player) removePlayer(player.id);
  });

  ws.on('error', () => {
    if (player) removePlayer(player.id);
  });
});

setInterval(gameLoop, 1000 / TICK_RATE);

server.listen(PORT, () => {
  console.log(`RTS WebSocket server listening on :${PORT}`);
});